import axios from 'axios';

// הגדרת הכתובת הבסיסית - התיקון שעשינו קודם
axios.defaults.baseURL = "http://localhost:5024";

// הוספת interceptor לתפיסת שגיאות (המורה ביקשה את זה)
axios.interceptors.response.use(
    response => response,
    error => {
        console.error("שגיאת API:", error);
        return Promise.reject(error);
    }
);

export default {
    // שליפת משימות
    getTasks: async () => {
        const result = await axios.get(`/items`);    
        return result.data;
    },

    // הוספת משימה חדשה
    addTask: async (name) => {
        // שולח אובייקט עם שם המשימה וסטטוס "לא בוצע"
        const result = await axios.post(`/items`, { name: name, isComplete: false });
        return result.data;
    },

    // עדכון סטטוס משימה
    setCompleted: async (id, isComplete) => {
        // שולח בקשת עדכון לשרת לפי ה-ID
        const result = await axios.put(`/items/${id}`, { isComplete: isComplete });
        return result.data;
    },

    // מחיקת משימה
    deleteTask: async (id) => {
        const result = await axios.delete(`/items/${id}`);
        return result.data;
    }
};
